#include <bits/stdc++.h>
using namespace std;
const int N=200005;
int t[N];
bool flag[N];
int dfn[N],n,ans=0x3f3f3f3f;
void dfs(int num,int step)
{
    if(flag[num]) return ;
    if(dfn[num])
    {
        ans=min(ans,step-dfn[num]);
    }
    else
    {
        dfn[num]=step;
        dfs(t[num],step+1);
        flag[num]=1;
    }
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>t[i];
    }
    for(int i=1;i<=n;i++)
    {
        dfs(i,0);
    }
    cout<<ans;
    return 0;
}
